/* CDPSE :: content/labs.js — CDPSE hands-on sandbox labs (20). */
window.LABS = [
{"id":"Lab 01","num":1,"group":"GOVERNANCE","title":"Stand Up the Privacy Program's Roles and Responsibilities","desc":"A mid-size healthtech firm has never had a formal privacy function. The general counsel has asked you, the incoming Data Privacy Solutions Engineer, to define who owns privacy decisions before a single control is built.","objectives":["Distinguish the DPO's independent oversight role from operational privacy engineering duties","Recognize that privacy accountability must be assigned to a specific accountable role, not shared ambiguously","Confirm reporting lines that preserve the DPO's independence from the functions it oversees"],"console":{"host":"cdpse-lab01","boot":["[SYS] privacy-governance-console v1.0 initializing","[SYS] loading org chart and RACI draft","[SYS] DPO charter template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the role responsible for independent privacy oversight"},{"id":"t2","label":"Choose how privacy accountability should be assigned"},{"id":"t3","label":"Choose the reporting line that preserves DPO independence"}],"configs":[{"id":"c1","label":"Who should hold independent oversight of the privacy program?","options":["A designated Data Protection Officer (DPO) with a direct line to senior leadership","The engineering team lead who builds the products","The marketing department, since it uses the most personal data","No one; oversight is unnecessary if controls exist"],"correct":"A designated Data Protection Officer (DPO) with a direct line to senior leadership","task":"t1"},{"id":"c2","label":"How should accountability for privacy decisions be assigned?","options":["To a specific, named accountable role documented in a RACI","Diffusely across all employees equally","To whichever team is easiest to blame later","It should remain undocumented for flexibility"],"correct":"To a specific, named accountable role documented in a RACI","task":"t2"},{"id":"c3","label":"Where should the DPO report to preserve independence?","options":["Directly to senior management or the board, outside the business units it oversees","Into the marketing department it audits","Into the engineering manager whose code it reviews","Nowhere; the DPO should be fully autonomous with no reporting line"],"correct":"Directly to senior management or the board, outside the business units it oversees","task":"t3"}],"payload":{"label":"RUN the governance charter validation","placeholder":"validate-charter --role dpo","button":"Run","response":"[OUT] DPO charter validated: independent reporting line to the board confirmed; accountability matrix assigns named owners for 6 privacy domains. Conclusion: governance structure meets independence and accountability requirements."}}},
{"id":"Lab 02","num":2,"group":"GOVERNANCE","title":"Differentiate the Privacy Notice from the Internal Privacy Policy","desc":"A product manager wants to publish one document that serves as both the customer-facing privacy notice and the internal privacy policy to save time. You must explain why these are different instruments with different audiences and enforce the distinction before publication.","objectives":["Distinguish the external, plain-language privacy notice from the internal, control-oriented privacy policy","Confirm the privacy notice discloses actual data practices in language a data subject can understand","Confirm the internal policy defines enforceable rules and control ownership for staff"],"console":{"host":"cdpse-lab02","boot":["[SYS] privacy-governance-console v1.0 initializing","[SYS] loading draft notice and draft policy","[SYS] readability scorer attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct audience for the privacy notice"},{"id":"t2","label":"Choose what the privacy notice must accurately reflect"},{"id":"t3","label":"Choose what the internal privacy policy defines that the notice does not"}],"configs":[{"id":"c1","label":"Who is the primary audience for the privacy notice?","options":["External data subjects, in plain and accessible language","Internal auditors only","Regulators exclusively, in legal jargon","The engineering team's code reviewers"],"correct":"External data subjects, in plain and accessible language","task":"t1"},{"id":"c2","label":"What must the privacy notice accurately reflect?","options":["The organization's actual data collection, use, and sharing practices","Only the practices the organization aspires to someday adopt","Whatever competitors publish in their own notices","Marketing claims about the product"],"correct":"The organization's actual data collection, use, and sharing practices","task":"t2"},{"id":"c3","label":"What does the internal privacy policy define that the public notice does not?","options":["Enforceable internal rules, control ownership, and staff obligations","Nothing; the two documents should be identical","The company's stock ticker and financial guidance","Customer support phone numbers"],"correct":"Enforceable internal rules, control ownership, and staff obligations","task":"t3"}],"payload":{"label":"RUN the notice-vs-policy consistency check","placeholder":"compare-docs --notice public --policy internal","button":"Run","response":"[OUT] Comparison complete: public notice matches actual data flows verified against the RoPA; internal policy adds control ownership and enforcement detail absent from the notice. Conclusion: two distinct, non-substitutable documents are required."}}},
{"id":"Lab 03","num":3,"group":"GOVERNANCE","title":"Determine the Lawful Basis Before Processing Begins","desc":"A growth team wants to launch a feature that profiles users for targeted offers using data collected at signup for account security. No one has confirmed whether the original lawful basis covers this new use, and the launch is scheduled for next week.","objectives":["Recognize that a lawful basis must be identified before processing begins, not retrofitted after launch","Confirm that a new purpose incompatible with the original basis requires a fresh lawful basis or consent","Distinguish consent from other lawful bases such as legitimate interest and contract necessity"],"console":{"host":"cdpse-lab03","boot":["[SYS] privacy-governance-console v1.0 initializing","[SYS] loading original collection purpose log","[SYS] proposed feature spec attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose when the lawful basis must be determined"},{"id":"t2","label":"Choose what is required when a new, incompatible purpose is proposed"},{"id":"t3","label":"Choose the lawful basis that requires a freely given, specific, informed action"}],"configs":[{"id":"c1","label":"When must the lawful basis for processing be determined?","options":["Before processing begins, at the point purposes are defined","After the feature has already launched","Only if a regulator asks","Whenever it is convenient for the sprint schedule"],"correct":"Before processing begins, at the point purposes are defined","task":"t1"},{"id":"c2","label":"The new profiling use is incompatible with the original security purpose. What is required?","options":["A fresh lawful basis (e.g., new consent) covering the new purpose","Nothing, since the data was already collected legitimately","A note in the engineering wiki is sufficient","Silent adoption, since users already agreed to the terms once"],"correct":"A fresh lawful basis (e.g., new consent) covering the new purpose","task":"t2"},{"id":"c3","label":"Which lawful basis specifically requires a freely given, specific, informed, and unambiguous action by the data subject?","options":["Consent","Legitimate interest","Contract necessity","Legal obligation"],"correct":"Consent","task":"t3"}],"payload":{"label":"RUN the purpose-compatibility assessment","placeholder":"assess-basis --purpose targeted-offers","button":"Run","response":"[OUT] Assessment complete: proposed profiling purpose is incompatible with original security-only basis; no valid lawful basis currently covers it. Conclusion: launch blocked pending fresh consent capture."}}},
{"id":"Lab 04","num":4,"group":"GOVERNANCE","title":"Handle a Data Subject Access Request Under Deadline","desc":"An individual has submitted a request asking what personal data the company holds about them and asking for a copy. Support wants to close the ticket with a form email, but the request must be verified, scoped, and fulfilled within the regulatory deadline.","objectives":["Verify the requester's identity before disclosing any personal data","Scope the search across all systems of record, not just the primary customer database","Fulfill or lawfully deny the request within the applicable statutory timeframe and document the decision"],"console":{"host":"cdpse-lab04","boot":["[SYS] rights-management-console v2.1 initializing","[SYS] DSAR intake ticket #4471 loaded","[SYS] system-of-record inventory attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the first step before disclosing any data"},{"id":"t2","label":"Choose the correct scope for the search"},{"id":"t3","label":"Choose what must happen within the statutory deadline"}],"configs":[{"id":"c1","label":"What must happen before any personal data is disclosed in response to the request?","options":["The requester's identity must be verified","The data should be emailed immediately to build goodwill","The request should be ignored until the requester escalates","The support agent should guess based on the email address alone"],"correct":"The requester's identity must be verified","task":"t1"},{"id":"c2","label":"What is the correct scope for the DSAR search?","options":["All systems of record known to hold personal data about the individual, per the data inventory","Only the primary CRM, since that is the easiest system to query","Only paper records","Only data collected in the last 30 days"],"correct":"All systems of record known to hold personal data about the individual, per the data inventory","task":"t2"},{"id":"c3","label":"What must occur within the applicable statutory deadline?","options":["A documented fulfillment, extension, or lawful denial of the request","Nothing formal, as long as the requester eventually stops asking","An internal apology email only","A price quote for expedited service"],"correct":"A documented fulfillment, extension, or lawful denial of the request","task":"t3"}],"payload":{"label":"RUN the DSAR fulfillment workflow","placeholder":"fulfill-dsar --ticket 4471","button":"Run","response":"[OUT] Identity verified via two-factor match; search executed across 5 systems of record; response compiled and logged 9 days before the statutory deadline. Conclusion: DSAR fulfilled compliantly and with an audit trail."}}},
{"id":"Lab 05","num":5,"group":"RISK & COMPLIANCE","title":"Scope a Data Protection Impact Assessment", "desc":"A new biometric attendance system is being proposed for all office locations. The project team wants to skip the privacy assessment because 'it is just a timeclock,' but the processing involves special-category data at scale and high potential impact.","objectives":["Recognize the triggers that make a DPIA mandatory, including special-category data and systematic monitoring","Scope the DPIA to cover the processing operation, not just the technology component","Confirm the DPIA is completed before processing begins, feeding into a go/no-go decision"],"console":{"host":"cdpse-lab05","boot":["[SYS] risk-assessment-console v2.0 initializing","[SYS] project intake form loaded","[SYS] DPIA trigger checklist attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the trigger that makes a DPIA mandatory here"},{"id":"t2","label":"Choose the correct scope for the assessment"},{"id":"t3","label":"Choose when the DPIA output must feed into the decision"}],"configs":[{"id":"c1","label":"Which factor makes a DPIA mandatory for this biometric system?","options":["Large-scale processing of special-category biometric data with high risk of harm","The vendor offers a discount for early adopters","The system uses a cloud provider","The project has a tight deadline"],"correct":"Large-scale processing of special-category biometric data with high risk of harm","task":"t1"},{"id":"c2","label":"What should the DPIA scope cover?","options":["The full processing operation: collection, storage, use, sharing, and retention of the biometric data","Only the hardware specifications of the timeclock device","Only the vendor's marketing brochure","Only the IT helpdesk's support process"],"correct":"The full processing operation: collection, storage, use, sharing, and retention of the biometric data","task":"t2"},{"id":"c3","label":"When must the DPIA findings inform the project decision?","options":["Before processing begins, as part of a go/no-go and risk-mitigation decision","After the system has been fully rolled out to all offices","Only if employees file a complaint","Never; the DPIA is a paperwork formality with no bearing on the launch"],"correct":"Before processing begins, as part of a go/no-go and risk-mitigation decision","task":"t3"}],"payload":{"label":"RUN the DPIA trigger and scoping check","placeholder":"scope-dpia --project biometric-timeclock","button":"Run","response":"[OUT] Trigger criteria met: special-category data, systematic monitoring, large scale. Scope set to full processing lifecycle. Conclusion: DPIA required and must complete before deployment approval."}}},
{"id":"Lab 06","num":6,"group":"RISK & COMPLIANCE","title":"Identify Privacy Threats and Harms, Not Just Security Threats","desc":"A security team's threat model for a new mobile app lists only confidentiality, integrity, and availability risks. The privacy engineering review must add the harms that matter to data subjects even when a system is functioning exactly as designed.","objectives":["Distinguish privacy harms (e.g., loss of autonomy, discrimination, unwanted disclosure) from security harms (e.g., breach, tampering)","Recognize that privacy harm can occur through lawful, intended processing, not only through attack or failure","Map identified privacy harms to specific mitigating controls before launch"],"console":{"host":"cdpse-lab06","boot":["[SYS] risk-assessment-console v2.0 initializing","[SYS] existing CIA threat model loaded","[SYS] privacy harm taxonomy attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the category of harm missing from the security-only threat model"},{"id":"t2","label":"Choose how privacy harm can occur even without a breach"},{"id":"t3","label":"Choose what each identified harm must be linked to"}],"configs":[{"id":"c1","label":"What category of harm is missing from a threat model limited to confidentiality, integrity, and availability?","options":["Privacy harms such as loss of autonomy, discrimination, or unwanted disclosure from intended use","Financial loss to shareholders","Server downtime costs","Trademark infringement risk"],"correct":"Privacy harms such as loss of autonomy, discrimination, or unwanted disclosure from intended use","task":"t1"},{"id":"c2","label":"How can a privacy harm occur even when the system works exactly as designed and is not breached?","options":["Through lawful, intended processing that still produces an adverse effect on the data subject, such as profiling-driven exclusion","Only through external attackers exploiting a vulnerability","Only through hardware failure","Privacy harm cannot occur without a breach"],"correct":"Through lawful, intended processing that still produces an adverse effect on the data subject, such as profiling-driven exclusion","task":"t2"},{"id":"c3","label":"What must each identified privacy harm be linked to?","options":["A specific mitigating control tracked to closure before launch","A press release reassuring customers","Nothing; identification alone satisfies the review","A future roadmap item with no owner or date"],"correct":"A specific mitigating control tracked to closure before launch","task":"t3"}],"payload":{"label":"RUN the privacy harm identification scan","placeholder":"scan-harms --app mobile-companion","button":"Run","response":"[OUT] 4 privacy harms identified beyond the CIA model: profiling bias, location inference, unwanted disclosure to third-party SDKs, loss of user control over settings. Each mapped to a mitigating control. Conclusion: threat model expanded to cover privacy-specific harm."}}},
{"id":"Lab 07","num":7,"group":"RISK & COMPLIANCE","title":"Map Privacy Controls to NIST Privacy Framework and ISO/IEC 27701", "desc":"Leadership wants a single control set that satisfies both the NIST Privacy Framework's outcome-based approach and the certifiable requirements of ISO/IEC 27701, without building two parallel compliance programs.","objectives":["Recognize the NIST Privacy Framework as a voluntary, outcome-based structure (Identify-Govern-Control-Communicate-Protect)","Recognize ISO/IEC 27701 as a certifiable extension to ISO/IEC 27001 for privacy information management","Cross-map control objectives so a single control satisfies requirements in both frameworks where they overlap"],"console":{"host":"cdpse-lab07","boot":["[SYS] framework-mapping-console v1.3 initializing","[SYS] NIST Privacy Framework core loaded","[SYS] ISO/IEC 27701 control catalog loaded","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct description of the NIST Privacy Framework"},{"id":"t2","label":"Choose the correct description of ISO/IEC 27701"},{"id":"t3","label":"Choose the right approach to avoid duplicate compliance programs"}],"configs":[{"id":"c1","label":"What best describes the NIST Privacy Framework?","options":["A voluntary, outcome-based framework organized around functions like Identify, Govern, Control, Communicate, and Protect","A mandatory US federal law with criminal penalties","A certification body that audits companies directly","A single technical encryption standard"],"correct":"A voluntary, outcome-based framework organized around functions like Identify, Govern, Control, Communicate, and Protect","task":"t1"},{"id":"c2","label":"What best describes ISO/IEC 27701?","options":["A certifiable privacy information management extension built on top of ISO/IEC 27001","A replacement for all data protection law","A US-only framework with no international recognition","A framework focused solely on marketing consent banners"],"correct":"A certifiable privacy information management extension built on top of ISO/IEC 27001","task":"t2"},{"id":"c3","label":"How should the organization avoid running two parallel compliance programs?","options":["Cross-map overlapping control objectives so one control set produces evidence for both frameworks","Pick one framework at random and ignore the other entirely","Duplicate every control and maintain two completely separate evidence sets","Outsource all mapping decisions to marketing"],"correct":"Cross-map overlapping control objectives so one control set produces evidence for both frameworks","task":"t3"}],"payload":{"label":"RUN the cross-framework control mapping","placeholder":"map-controls --frameworks nist-pf,iso27701","button":"Run","response":"[OUT] 38 of 45 control objectives cross-mapped as equivalent; 7 framework-specific gaps flagged for supplemental controls. Conclusion: unified control set satisfies both frameworks with no duplicated program."}}},
{"id":"Lab 08","num":8,"group":"RISK & COMPLIANCE","title":"Build Accountability Evidence with a Record of Processing Activities", "desc":"An external auditor has asked the organization to demonstrate accountability for its data processing. The team has controls in place but no consolidated Record of Processing Activities (RoPA), so there is no single source of truth to show the auditor.","objectives":["Recognize the RoPA as the foundational accountability artifact linking purposes, data categories, and legal bases","Confirm the RoPA is kept current as processing activities change, not created once and forgotten","Use the RoPA as the evidence base for demonstrating accountability to regulators and auditors"],"console":{"host":"cdpse-lab08","boot":["[SYS] accountability-console v1.4 initializing","[SYS] processing activity interviews loaded","[SYS] RoPA template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what the RoPA must link together"},{"id":"t2","label":"Choose how often the RoPA should be updated"},{"id":"t3","label":"Choose what the RoPA is used for during an audit"}],"configs":[{"id":"c1","label":"What must the Record of Processing Activities link together?","options":["Processing purposes, data categories, recipients, retention, and the applicable lawful basis","Only employee names and job titles","Only the company's marketing calendar","Only server IP addresses"],"correct":"Processing purposes, data categories, recipients, retention, and the applicable lawful basis","task":"t1"},{"id":"c2","label":"How often should the RoPA be updated?","options":["Continuously, whenever processing activities change, not just at initial creation","Once, at company founding, and never again","Only when a regulator sends a fine notice","Every ten years on a fixed schedule regardless of change"],"correct":"Continuously, whenever processing activities change, not just at initial creation","task":"t2"},{"id":"c3","label":"What role does the RoPA play during an accountability audit?","options":["The primary evidence base demonstrating what data is processed, why, and under what basis","A decorative document with no bearing on the audit outcome","A substitute for having any actual controls in place","A tool used only by the marketing department"],"correct":"The primary evidence base demonstrating what data is processed, why, and under what basis","task":"t3"}],"payload":{"label":"RUN the RoPA completeness audit","placeholder":"audit-ropa --scope enterprise","button":"Run","response":"[OUT] RoPA populated for 27 processing activities; 3 stale entries flagged for update; lawful basis field complete for all entries. Conclusion: RoPA is audit-ready and serves as the accountability evidence base."}}},
{"id":"Lab 09","num":9,"group":"DATA LIFE CYCLE","title":"Map and Classify Personal Data Across the Environment", "desc":"A company acquired through merger has personal data scattered across legacy databases, spreadsheets, and a new SaaS CRM, with no consolidated inventory. You must build a data map and classification scheme before any lifecycle controls can be applied.","objectives":["Discover and inventory personal data across structured and unstructured repositories","Classify data by sensitivity, including special categories requiring heightened protection","Use the completed data map as the foundation for all downstream lifecycle controls"],"console":{"host":"cdpse-lab09","boot":["[SYS] data-mapping-console v2.2 initializing","[SYS] discovery scan across 14 repositories queued","[SYS] classification schema loaded","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct first step before classification"},{"id":"t2","label":"Choose the classification tier for special-category data"},{"id":"t3","label":"Choose what the data map becomes the foundation for"}],"configs":[{"id":"c1","label":"What must happen before data can be classified?","options":["Discovery and inventory of personal data across all structured and unstructured repositories","Immediate deletion of anything found in a spreadsheet","Publishing the privacy notice","Hiring outside counsel"],"correct":"Discovery and inventory of personal data across all structured and unstructured repositories","task":"t1"},{"id":"c2","label":"How should special-category data (e.g., health, biometric) be classified?","options":["At the highest sensitivity tier, requiring heightened protection and handling controls","At the same tier as public marketing content","It should not be classified at all","At the lowest tier, since it is only used internally"],"correct":"At the highest sensitivity tier, requiring heightened protection and handling controls","task":"t2"},{"id":"c3","label":"What is the completed data map the foundation for?","options":["All downstream lifecycle controls: minimization, retention, transfer, and destruction decisions","A one-time slide for the board and nothing further","The company's advertising strategy","Nothing; it is an isolated compliance artifact"],"correct":"All downstream lifecycle controls: minimization, retention, transfer, and destruction decisions","task":"t3"}],"payload":{"label":"RUN the data discovery and classification scan","placeholder":"scan-data --scope merged-environment","button":"Run","response":"[OUT] Discovery scan found personal data in 14 repositories including 2 previously unknown spreadsheets; special-category health data flagged and tagged at highest sensitivity. Conclusion: baseline data map established for lifecycle control design."}}},
{"id":"Lab 10","num":10,"group":"DATA LIFE CYCLE","title":"Apply Data Minimization Before a New Field Ships", "desc":"A signup form under development collects date of birth, full home address, and government ID number, but the feature only needs to confirm the user is over 18. Product wants to keep the extra fields 'in case they're useful later.'","objectives":["Apply the minimization principle: collect only what is necessary for the stated purpose","Reject speculative 'might need it later' data collection as a justification","Recommend a privacy-preserving alternative that satisfies the actual business need"],"console":{"host":"cdpse-lab10","boot":["[SYS] lifecycle-console v1.8 initializing","[SYS] signup form field spec loaded","[SYS] minimization checklist attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct minimization principle to apply"},{"id":"t2","label":"Choose whether 'might be useful later' justifies collection"},{"id":"t3","label":"Choose the minimized alternative that meets the actual purpose"}],"configs":[{"id":"c1","label":"What principle should govern which fields the signup form collects?","options":["Collect only the data necessary for the stated, specific purpose","Collect as much as possible for future flexibility","Collect whatever competitors collect","Collect everything the database schema allows"],"correct":"Collect only the data necessary for the stated, specific purpose","task":"t1"},{"id":"c2","label":"Does 'we might need it later' justify collecting the ID number and full address now?","options":["No; speculative future use does not justify collection without a defined current purpose","Yes, it is always fine to collect more data than needed just in case","Yes, but only on Tuesdays","No, but only because storage is expensive"],"correct":"No; speculative future use does not justify collection without a defined current purpose","task":"t2"},{"id":"c3","label":"What minimized alternative satisfies the actual need to confirm the user is over 18?","options":["A simple age or date-of-birth confirmation without collecting ID number or full address","Collecting the full government ID number and scanning it","Collecting the user's home address history for the past ten years","Requiring a notarized birth certificate upload"],"correct":"A simple age or date-of-birth confirmation without collecting ID number or full address","task":"t3"}],"payload":{"label":"RUN the field-level minimization review","placeholder":"review-fields --form signup-v2","button":"Run","response":"[OUT] Review complete: government ID and full address fields removed; date-of-birth field retained solely for age-gate logic. Conclusion: form now collects the minimum data necessary for its stated purpose."}}},
{"id":"Lab 11","num":11,"group":"DATA LIFE CYCLE","title":"Set a Defensible Retention Schedule", "desc":"A legal hold was recently lifted, and the team discovered customer records dating back 14 years with no retention schedule ever applied. You must define and implement retention periods tied to actual business and legal need rather than 'keep everything forever.'","objectives":["Tie each data category's retention period to a specific legal, regulatory, or business justification","Reject indefinite retention as a default posture","Implement a defensible deletion or archival process once the retention period expires"],"console":{"host":"cdpse-lab11","boot":["[SYS] lifecycle-console v1.8 initializing","[SYS] 14-year records inventory loaded","[SYS] retention schedule template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what each retention period must be justified by"},{"id":"t2","label":"Choose whether indefinite retention is an acceptable default"},{"id":"t3","label":"Choose what must happen once the retention period expires"}],"configs":[{"id":"c1","label":"What must justify the retention period assigned to a data category?","options":["A specific legal, regulatory, or documented business need","Whatever period makes the storage bill lowest","A guess based on how the last company did it","No justification is required if storage is cheap"],"correct":"A specific legal, regulatory, or documented business need","task":"t1"},{"id":"c2","label":"Is 'keep everything indefinitely' an acceptable default retention posture?","options":["No; indefinite retention without justification increases risk and is not defensible","Yes, because more data is always more valuable","Yes, but only for customer records","Yes, as long as it is encrypted"],"correct":"No; indefinite retention without justification increases risk and is not defensible","task":"t2"},{"id":"c3","label":"What must happen once a record's retention period expires?","options":["A defensible deletion or archival process is executed and logged","Nothing; expiration is purely informational","The record is emailed to the original customer","The record is made public"],"correct":"A defensible deletion or archival process is executed and logged","task":"t3"}],"payload":{"label":"RUN the retention schedule enforcement job","placeholder":"enforce-retention --category customer-records","button":"Run","response":"[OUT] Retention schedule applied: 7-year legal basis assigned to financial records, 3-year to marketing contacts; 14-year-old records beyond all justified periods queued for defensible deletion. Conclusion: retention now tied to documented need, not indefinite default."}}},
{"id":"Lab 12","num":12,"group":"DATA LIFE CYCLE","title":"Select a Lawful Mechanism for Cross-Border Data Transfer", "desc":"The company plans to move customer support data processing to a vendor in a country without an adequacy decision. The vendor contract is ready to sign, but no transfer mechanism has been evaluated to make the transfer lawful.","objectives":["Recognize that transferring personal data across a border into a jurisdiction without an adequacy decision requires a valid transfer mechanism","Evaluate standard contractual clauses (SCCs) or binding corporate rules as mechanisms, backed by a transfer impact assessment","Confirm the mechanism is documented and executed before the transfer begins, not after"],"console":{"host":"cdpse-lab12","boot":["[SYS] lifecycle-console v1.8 initializing","[SYS] vendor jurisdiction lookup loaded","[SYS] transfer mechanism options attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose why a transfer mechanism is needed here"},{"id":"t2","label":"Choose a valid transfer mechanism supported by an impact assessment"},{"id":"t3","label":"Choose when the mechanism must be in place"}],"configs":[{"id":"c1","label":"Why does this transfer require a specific lawful mechanism?","options":["The destination country lacks an adequacy decision, so an alternative safeguard is required for the transfer to be lawful","Because the vendor asked for one out of courtesy","Transfers within a single vendor relationship never need a mechanism","Because the data is encrypted, no mechanism is ever needed"],"correct":"The destination country lacks an adequacy decision, so an alternative safeguard is required for the transfer to be lawful","task":"t1"},{"id":"c2","label":"Which is a valid mechanism to lawfully support this cross-border transfer?","options":["Standard contractual clauses (SCCs) supported by a transfer impact assessment","A verbal assurance from the vendor's sales representative","Posting a notice on the company blog","Relying solely on the vendor's own internal privacy policy"],"correct":"Standard contractual clauses (SCCs) supported by a transfer impact assessment","task":"t2"},{"id":"c3","label":"When must the transfer mechanism be documented and executed?","options":["Before the cross-border transfer begins","Any time within the following two years","Only if a regulator requests it after the fact","Never; it is optional paperwork"],"correct":"Before the cross-border transfer begins","task":"t3"}],"payload":{"label":"RUN the cross-border transfer mechanism check","placeholder":"validate-transfer --vendor support-saas-intl","button":"Run","response":"[OUT] Adequacy decision absent for destination country; SCCs executed and transfer impact assessment completed identifying supplementary encryption measure. Conclusion: transfer mechanism validated and in place prior to go-live."}}},
{"id":"Lab 13","num":13,"group":"DATA LIFE CYCLE","title":"Verify Secure Destruction and De-identification at End of Life", "desc":"A decommissioned analytics platform still holds five years of customer behavioral data. The vendor claims the data was 'deleted,' but there is no verification that destruction was complete or that any retained data was properly de-identified for research use.","objectives":["Confirm secure destruction is verified with evidence, not merely asserted by a vendor","Distinguish deletion (irreversible destruction) from de-identification (data retained but stripped of identifying linkage)","Assess whether de-identified data could still be re-identified given auxiliary data sources"],"console":{"host":"cdpse-lab13","boot":["[SYS] lifecycle-console v1.8 initializing","[SYS] vendor destruction attestation loaded","[SYS] re-identification risk model attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what is required to confirm destruction actually occurred"},{"id":"t2","label":"Choose the correct distinction between deletion and de-identification"},{"id":"t3","label":"Choose what must be assessed for any retained de-identified data"}],"configs":[{"id":"c1","label":"What is required to confirm the vendor actually destroyed the data?","options":["Documented, verifiable evidence of destruction (e.g., certificate of destruction, audit log), not a verbal claim alone","A verbal assurance from the vendor's account manager","Nothing further; vendor claims are always sufficient","A single email confirming the request was submitted"],"correct":"Documented, verifiable evidence of destruction (e.g., certificate of destruction, audit log), not a verbal claim alone","task":"t1"},{"id":"c2","label":"What is the correct distinction between deletion and de-identification?","options":["Deletion irreversibly destroys the data, while de-identification retains data but removes identifying linkage","They are the same process with different names","De-identification is more secure than deletion in every case","Deletion only applies to paper records"],"correct":"Deletion irreversibly destroys the data, while de-identification retains data but removes identifying linkage","task":"t2"},{"id":"c3","label":"What must be assessed for any retained de-identified data?","options":["The residual risk of re-identification using auxiliary or publicly available data sources","Only its file size on disk","Only whether it is stored in the cloud or on-premises","Nothing further once the identifiers are removed"],"correct":"The residual risk of re-identification using auxiliary or publicly available data sources","task":"t3"}],"payload":{"label":"RUN the destruction verification and re-identification risk scan","placeholder":"verify-destruction --system legacy-analytics","button":"Run","response":"[OUT] Certificate of destruction obtained and cross-checked against storage logs; retained research dataset re-identification risk assessed as low but non-zero given auxiliary location data. Conclusion: destruction verified; residual re-identification risk flagged for additional generalization."}}},
{"id":"Lab 14","num":14,"group":"PRIVACY ENGINEERING","title":"Design Least-Privilege Access to Personal Data", "desc":"An internal review finds that 80% of customer support staff have standing access to full payment card and health data fields, even though fewer than 5% ever need them to resolve a ticket. You must redesign access controls around least privilege and role-based need.","objectives":["Design role-based access so each role sees only the personal data fields necessary for its function","Replace standing broad access with attribute- or context-based access granted only when justified","Implement periodic access recertification to catch privilege creep over time"],"console":{"host":"cdpse-lab14","boot":["[SYS] privacy-engineering-console v3.1 initializing","[SYS] access entitlement report loaded","[SYS] role-field mapping template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the access model that limits exposure to necessary fields"},{"id":"t2","label":"Choose the replacement for standing broad access"},{"id":"t3","label":"Choose the control that catches privilege creep over time"}],"configs":[{"id":"c1","label":"What access model limits each role to only the personal data fields it needs?","options":["Role-based access control mapped field-by-field to job function","Granting every employee administrator rights for convenience","A single shared login used by the whole support team","No access model; rely on staff honesty"],"correct":"Role-based access control mapped field-by-field to job function","task":"t1"},{"id":"c2","label":"What should replace standing broad access to sensitive fields like payment card and health data?","options":["Just-in-time, context-based access granted only when a specific justified need arises","Making the broad access permanent for all new hires too","Removing all access controls to speed up ticket resolution","Granting broad access only to managers instead of staff"],"correct":"Just-in-time, context-based access granted only when a specific justified need arises","task":"t2"},{"id":"c3","label":"What control catches privilege creep after roles change over time?","options":["Periodic access recertification reviewed against current job function","A one-time access grant at hiring with no further review","Annual company picnic attendance records","Nothing; access rights should never be revisited"],"correct":"Periodic access recertification reviewed against current job function","task":"t3"}],"payload":{"label":"RUN the least-privilege access redesign","placeholder":"redesign-access --team support","button":"Run","response":"[OUT] Field-level RBAC applied: payment card and health fields restricted to 4% of support roles requiring them; just-in-time elevation enabled for edge cases; quarterly recertification scheduled. Conclusion: standing over-privileged access eliminated."}}},
{"id":"Lab 15","num":15,"group":"PRIVACY ENGINEERING","title":"Implement Encryption and Key Management for Personal Data", "desc":"A database holding customer profiles is encrypted at rest, but the encryption keys are stored in the same database instance alongside the data they protect, and the same key has been used unrotated since the system launched three years ago.","objectives":["Separate encryption keys from the data they protect using a dedicated key management service","Implement periodic key rotation to limit the impact of a potential key compromise","Apply encryption in transit as well as at rest for personal data flows"],"console":{"host":"cdpse-lab15","boot":["[SYS] privacy-engineering-console v3.1 initializing","[SYS] encryption architecture diagram loaded","[SYS] key management options attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose where encryption keys should be stored relative to the data"},{"id":"t2","label":"Choose the control that limits the impact of key compromise"},{"id":"t3","label":"Choose the additional encryption coverage needed beyond at-rest"}],"configs":[{"id":"c1","label":"Where should encryption keys be stored relative to the data they protect?","options":["Separated in a dedicated key management service, not co-located with the protected data","In the same database table as the encrypted records","In a plaintext configuration file checked into source control","Emailed to the database administrator for safekeeping"],"correct":"Separated in a dedicated key management service, not co-located with the protected data","task":"t1"},{"id":"c2","label":"What control limits the damage if an encryption key is ever compromised?","options":["Periodic key rotation with defined key lifecycles","Using the same key forever so staff don't need to relearn procedures","Disabling encryption to simplify key management","Sharing the key across every environment including test and production"],"correct":"Periodic key rotation with defined key lifecycles","task":"t2"},{"id":"c3","label":"Beyond encryption at rest, what else must be protected for personal data flows?","options":["Encryption in transit for data moving across networks","Nothing; at-rest encryption alone is always sufficient","Only backup tapes need encryption","Only data accessed from mobile devices needs encryption"],"correct":"Encryption in transit for data moving across networks","task":"t3"}],"payload":{"label":"RUN the encryption and key management remediation","placeholder":"remediate-keys --system customer-profile-db","button":"Run","response":"[OUT] Keys migrated to a dedicated KMS separate from the data store; automated 90-day rotation enabled; TLS enforced for all in-transit flows. Conclusion: encryption architecture now separates keys from data with rotation and transit coverage."}}},
{"id":"Lab 16","num":16,"group":"PRIVACY ENGINEERING","title":"Choose Between Anonymization and Pseudonymization for an Analytics Dataset", "desc":"A data science team wants to share a customer behavior dataset with an external research partner. They plan to simply remove the name and email fields and call it 'anonymized,' but the dataset still contains device ID, ZIP code, and birth date, which together can re-identify most individuals.","objectives":["Distinguish true anonymization (irreversible, no re-identification possible) from pseudonymization (reversible with a separately held key)","Recognize that removing direct identifiers alone does not achieve anonymization when quasi-identifiers remain","Select the technique appropriate to the actual risk and reversibility needs of the sharing use case"],"console":{"host":"cdpse-lab16","boot":["[SYS] privacy-engineering-console v3.1 initializing","[SYS] dataset field inventory loaded","[SYS] re-identification risk calculator attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the correct distinction between anonymization and pseudonymization"},{"id":"t2","label":"Choose why removing name and email alone is insufficient"},{"id":"t3","label":"Choose the technique appropriate for external research sharing without reversal need"}],"configs":[{"id":"c1","label":"What is the correct distinction between anonymization and pseudonymization?","options":["Anonymization is irreversible with no re-identification path; pseudonymization is reversible via a separately held key","They are interchangeable terms for the same technique","Pseudonymization is always irreversible and stronger than anonymization","Anonymization requires keeping a re-identification key on file"],"correct":"Anonymization is irreversible with no re-identification path; pseudonymization is reversible via a separately held key","task":"t1"},{"id":"c2","label":"Why is removing only the name and email fields insufficient to call this dataset anonymized?","options":["Remaining quasi-identifiers like device ID, ZIP code, and birth date can still re-identify most individuals in combination","Because name and email are not personal data in the first place","Because the research partner promised not to re-identify anyone","Removing those two fields is always sufficient regardless of what remains"],"correct":"Remaining quasi-identifiers like device ID, ZIP code, and birth date can still re-identify most individuals in combination","task":"t2"},{"id":"c3","label":"Given the research partner needs no ability to re-link records to individuals, which technique fits best?","options":["True anonymization with generalization or suppression of quasi-identifiers, since no reversal is needed","Pseudonymization with the key stored in the shared dataset itself","Leaving all identifiers in place for research convenience","Encryption alone with the key given to the research partner"],"correct":"True anonymization with generalization or suppression of quasi-identifiers, since no reversal is needed","task":"t3"}],"payload":{"label":"RUN the anonymization adequacy check","placeholder":"check-anonymization --dataset behavior-export","button":"Run","response":"[OUT] Quasi-identifier combination (device ID + ZIP + birth date) found to re-identify 91% of records; dataset reclassified as pseudonymized, not anonymized. Generalization applied to ZIP and birth date to reach true anonymization threshold. Conclusion: dataset now safe for external sharing without a re-identification key."}}},
{"id":"Lab 17","num":17,"group":"PRIVACY ENGINEERING","title":"Design a Consent Management and Cookie Banner Flow", "desc":"A website's current cookie banner has only an 'Accept' button, pre-checked boxes for advertising cookies, and no way to withdraw consent later. The compliance team has flagged it as a dark pattern that fails to capture valid consent.","objectives":["Design a consent mechanism that is freely given, specific, informed, and unambiguous, with equally prominent accept and reject options","Ensure non-essential cookies do not fire until affirmative consent is captured","Provide a mechanism for the data subject to withdraw consent as easily as it was given"],"console":{"host":"cdpse-lab17","boot":["[SYS] consent-management-console v2.0 initializing","[SYS] current cookie banner config loaded","[SYS] dark-pattern checklist attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the fix for the banner's asymmetric accept/reject design"},{"id":"t2","label":"Choose when non-essential cookies should be allowed to fire"},{"id":"t3","label":"Choose the requirement for withdrawing consent"}],"configs":[{"id":"c1","label":"How should the accept and reject options be presented to fix the dark pattern?","options":["With equal prominence and equally easy interaction, and no pre-checked boxes for non-essential categories","Keep 'Accept' large and colorful while hiding 'Reject' in a small gray link","Remove the reject option entirely to simplify the flow","Pre-check all categories so users don't have to think"],"correct":"With equal prominence and equally easy interaction, and no pre-checked boxes for non-essential categories","task":"t1"},{"id":"c2","label":"When should non-essential (e.g., advertising) cookies be allowed to fire?","options":["Only after the user gives affirmative, specific consent","Immediately on page load, before any user interaction","Only after the user has been on the site for five minutes","Whenever the marketing team prefers, regardless of consent state"],"correct":"Only after the user gives affirmative, specific consent","task":"t2"},{"id":"c3","label":"What must be true about withdrawing consent once given?","options":["Withdrawal must be as easy to exercise as giving consent was","Withdrawal should require a written letter mailed to headquarters","Withdrawal should not be offered at all once consent is given","Withdrawal should require a phone call during limited business hours only"],"correct":"Withdrawal must be as easy to exercise as giving consent was","task":"t3"}],"payload":{"label":"RUN the consent flow compliance check","placeholder":"validate-consent --surface cookie-banner","button":"Run","response":"[OUT] Banner redesigned: equal-weight Accept/Reject buttons, all non-essential categories default off, one-click withdrawal added to account settings. Conclusion: dark pattern remediated; consent now freely given, specific, and revocable."}}},
{"id":"Lab 18","num":18,"group":"PRIVACY ENGINEERING","title":"Select the Right Privacy-Enhancing Technology for the Use Case", "desc":"A finance team wants aggregate salary benchmarking across partner companies without any partner seeing another's raw employee data, while a product team separately wants to train a model on user data without centralizing raw records. Both ask you to 'just add encryption.'","objectives":["Match the privacy-enhancing technology (PET) to the actual risk and computation need rather than defaulting to one tool","Recognize secure multiparty computation as suited to joint computation without revealing raw inputs to any party","Recognize federated learning as suited to model training without centralizing raw personal data"],"console":{"host":"cdpse-lab18","boot":["[SYS] privacy-engineering-console v3.1 initializing","[SYS] PET comparison matrix loaded","[SYS] two use-case briefs attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the PET suited to joint salary benchmarking without revealing raw data to partners"},{"id":"t2","label":"Choose the PET suited to model training without centralizing raw user data"},{"id":"t3","label":"Choose why 'just add encryption' does not fully address either use case"}],"configs":[{"id":"c1","label":"Which PET lets partner companies jointly compute a salary benchmark without any partner seeing another's raw data?","options":["Secure multiparty computation (MPC)","A shared spreadsheet emailed between partners","Symmetric encryption with one shared key held by all partners","A single centralized database accessible to every partner"],"correct":"Secure multiparty computation (MPC)","task":"t1"},{"id":"c2","label":"Which PET allows model training across user devices without centralizing raw personal data?","options":["Federated learning","Uploading all raw data to a central server before training","Printing the training data to paper for manual review","Disabling the model entirely"],"correct":"Federated learning","task":"t2"},{"id":"c3","label":"Why is 'just add encryption' insufficient on its own for these two use cases?","options":["Encryption protects data at rest or in transit but does not, by itself, enable joint computation or decentralized training without exposing raw values","Encryption already solves every privacy problem in every scenario","Encryption is unnecessary once a PET is chosen","Encryption replaces the need for a lawful basis"],"correct":"Encryption protects data at rest or in transit but does not, by itself, enable joint computation or decentralized training without exposing raw values","task":"t3"}],"payload":{"label":"RUN the PET selection matrix","placeholder":"select-pet --usecases benchmarking,model-training","button":"Run","response":"[OUT] Secure multiparty computation recommended for salary benchmarking; federated learning recommended for model training. Encryption retained as a complementary control, not a substitute. Conclusion: PET selection matched to each computation need."}}},
{"id":"Lab 19","num":19,"group":"PRIVACY ENGINEERING","title":"Redesign Application Logging to Remove Unnecessary PII", "desc":"An incident responder discovers that application debug logs capture full request bodies, including passwords, full names, and payment tokens, in plaintext, and these logs are retained for two years in a system with broad developer access.","objectives":["Redesign logging to exclude or mask personal data fields that are not needed for operational troubleshooting","Apply field-level masking or tokenization for any personal data that must remain in logs","Align log retention and access with the sensitivity of any personal data that remains"],"console":{"host":"cdpse-lab19","boot":["[SYS] privacy-engineering-console v3.1 initializing","[SYS] log schema sample loaded","[SYS] masking rule library attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose what should happen to personal data fields not needed for troubleshooting"},{"id":"t2","label":"Choose the control for personal data that must remain in logs"},{"id":"t3","label":"Choose how log retention and access should be aligned"}],"configs":[{"id":"c1","label":"What should happen to personal data fields, like full request bodies with passwords, that are not needed for troubleshooting?","options":["They should be excluded from logs entirely at the point of capture","They should be logged in full for maximum debugging convenience","They should be logged only on weekends","They should be forwarded to a public dashboard for transparency"],"correct":"They should be excluded from logs entirely at the point of capture","task":"t1"},{"id":"c2","label":"For personal data that operationally must remain in logs, what control should be applied?","options":["Field-level masking or tokenization so the raw value is not exposed in plaintext","No control; operational necessity overrides all privacy concerns","Storing it in a second, less secure log file instead","Printing it to the console for easier developer visibility"],"correct":"Field-level masking or tokenization so the raw value is not exposed in plaintext","task":"t2"},{"id":"c3","label":"How should log retention and access be set once personal data is minimized in logs?","options":["Aligned with the sensitivity of any remaining personal data, with access restricted accordingly","Left at the broadest possible access and longest possible retention regardless of content","Retention should always default to indefinite for all logs","Access should be granted to all developers regardless of need"],"correct":"Aligned with the sensitivity of any remaining personal data, with access restricted accordingly","task":"t3"}],"payload":{"label":"RUN the logging remediation and masking rollout","placeholder":"remediate-logs --service checkout-api","button":"Run","response":"[OUT] Password and payment token fields excluded from log capture at the source; customer name field tokenized where retained for support use; log access restricted to on-call engineers with 90-day retention. Conclusion: logs minimized and access-aligned to remaining data sensitivity."}}},
{"id":"Lab 20","num":20,"group":"PRIVACY ENGINEERING","title":"Assess Privacy Risk in an AI/ML Feature Before Launch", "desc":"A customer-facing chatbot feature is being built on top of a large language model that will be fine-tuned using historical support tickets containing personal data. The engineering team wants to ship quickly and address privacy 'if a regulator asks.'","objectives":["Assess training-data privacy risk, including memorization and potential regurgitation of personal data in model outputs","Apply data minimization and de-identification to training data before fine-tuning begins, not afterward","Confirm data subject rights (e.g., access, deletion) can practically be honored for data used to train or operate the model"],"console":{"host":"cdpse-lab20","boot":["[SYS] privacy-engineering-console v3.1 initializing","[SYS] fine-tuning dataset sample loaded","[SYS] model risk assessment template attached","[SYS] ready"],"tasks":[{"id":"t1","label":"Choose the training-data risk that must be assessed before fine-tuning"},{"id":"t2","label":"Choose when minimization and de-identification must be applied"},{"id":"t3","label":"Choose what must be practically honorable once the model is trained"}],"configs":[{"id":"c1","label":"What training-data privacy risk must be assessed before this fine-tuning begins?","options":["The risk that the model memorizes and later regurgitates personal data from the training tickets in its outputs","Only the risk of the model producing grammatically incorrect responses","Only the risk of the model being too slow to respond","Only the risk of increased cloud compute costs"],"correct":"The risk that the model memorizes and later regurgitates personal data from the training tickets in its outputs","task":"t1"},{"id":"c2","label":"When should data minimization and de-identification be applied to the support ticket training data?","options":["Before fine-tuning begins, as part of the data preparation pipeline","After launch, only if a regulator opens an inquiry","Never; fine-tuning data is exempt from privacy requirements","Only after the first customer complaint is received"],"correct":"Before fine-tuning begins, as part of the data preparation pipeline","task":"t2"},{"id":"c3","label":"What must remain practically honorable once personal data has been used to train or operate the model?","options":["Data subject rights such as access and deletion requests affecting that data","Nothing; once data trains a model, all individual rights end permanently","Only the company's right to monetize the model","Only the rights of employees, not customers"],"correct":"Data subject rights such as access and deletion requests affecting that data","task":"t3"}],"payload":{"label":"RUN the AI/ML privacy risk assessment","placeholder":"assess-ai-risk --feature support-chatbot","button":"Run","response":"[OUT] Memorization risk identified for rare identifiers in ticket text; de-identification pipeline added before fine-tuning; deletion-request process extended to cover retraining exclusion lists. Conclusion: AI feature privacy risk mitigated prior to launch, with rights honored end to end."}}}
];
